const files = {
  "package.json": "{\n  \"name\": \"atomquest-frontend\",\n  \"version\": \"1.0.0\",\n  \"description\": \"\",\n  \"main\": \"index.js\",\n  \"scripts\": {\n    \"dev\": \"vite\",\n    \"build\": \"vite build\",\n    \"preview\": \"vite preview\"\n  },\n  \"keywords\": [],\n  \"author\": \"\",\n  \"license\": \"ISC\",\n  \"dependencies\": {\n    \"axios\": \"^1.16.1\",\n    \"lucide-react\": \"^1.16.0\",\n    \"react\": \"^19.2.6\",\n    \"react-dom\": \"^19.2.6\",\n    \"react-hot-toast\": \"^2.6.0\",\n    \"react-router-dom\": \"^7.15.1\"\n  },\n  \"devDependencies\": {\n    \"@vitejs/plugin-react\": \"^6.0.2\",\n    \"autoprefixer\": \"^10.5.0\",\n    \"postcss\": \"^8.5.14\",\n    \"tailwindcss\": \"^3.4.19\",\n    \"vite\": \"^8.0.13\"\n  },\n  \"type\": \"module\"\n}",
  "vite.config.js": "import { defineConfig } from 'vite'\nimport react from '@vitejs/plugin-react'\n\nexport default defineConfig({\n  plugins: [react()],\n  server: {\n    port: 5173,\n    proxy: {\n      '/api': {\n        target: 'http://localhost:3000',\n        changeOrigin: true,\n      },\n    },\n  },\n})\n",
  "index.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <title>AtomQuest \u2014 Goal Tracker</title>\n  </head>\n  <body>\n    <div id=\"root\"></div>\n    <script type=\"module\" src=\"/src/main.jsx\"></script>\n  </body>\n</html>\n",
  "tailwind.config.js": "/** @type {import('tailwindcss').Config} */\nmodule.exports = {\n  content: [],\n  theme: {\n    extend: {},\n  },\n  plugins: [],\n}\n\n",
  "postcss.config.js": "module.exports = {\n  plugins: {\n    tailwindcss: {},\n    autoprefixer: {},\n  },\n}\n",
  "src/index.css": "@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n@layer base {\n  body {\n    @apply bg-gray-50 text-gray-900 antialiased;\n  }\n}\n\n@layer components {\n  .btn-primary {\n    @apply bg-brand-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-brand-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed;\n  }\n  .btn-secondary {\n    @apply bg-white text-gray-700 px-4 py-2 rounded-lg text-sm font-medium border border-gray-300 hover:bg-gray-50 transition-colors;\n  }\n  .btn-danger {\n    @apply bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-700 transition-colors;\n  }\n  .card {\n    @apply bg-white rounded-xl shadow-sm border border-gray-200 p-6;\n  }\n  .input {\n    @apply w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-transparent;\n  }\n  .label {\n    @apply block text-sm font-medium text-gray-700 mb-1;\n  }\n  .badge-draft     { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-700; }\n  .badge-submitted { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-700; }\n  .badge-approved  { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-700; }\n  .badge-returned  { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-700; }\n}\n",
  "src/main.jsx": "import React from 'react'\nimport ReactDOM from 'react-dom/client'\nimport App from './App'\nimport './index.css'\n\nReactDOM.createRoot(document.getElementById('root')).render(\n  <React.StrictMode>\n    <App />\n  </React.StrictMode>\n)\n",
  "src/App.jsx": "import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom'\nimport { Toaster } from 'react-hot-toast'\nimport { AuthProvider, useAuth } from './context/AuthContext'\n\nimport Login from './pages/Login'\nimport Layout from './components/Layout'\n\n// Employee pages\nimport EmployeeDashboard from './pages/employee/Dashboard'\nimport MyGoalSheet from './pages/employee/MyGoalSheet'\nimport GoalSheetDetail from './pages/employee/GoalSheetDetail'\n\n// Manager pages\nimport ManagerDashboard from './pages/manager/Dashboard'\nimport TeamGoalSheets from './pages/manager/TeamGoalSheets'\nimport ReviewSheet from './pages/manager/ReviewSheet'\n\n// Admin pages\nimport AdminDashboard from './pages/admin/Dashboard'\nimport ManageUsers from './pages/admin/ManageUsers'\nimport ManageCycles from './pages/admin/ManageCycles'\nimport Reports from './pages/admin/Reports'\n\nconst ProtectedRoute = ({ children, roles }) => {\n  const { user, loading } = useAuth()\n  if (loading) return <div className=\"flex items-center justify-center h-screen\"><div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-brand-600\"/></div>\n  if (!user) return <Navigate to=\"/login\" replace />\n  if (roles && !roles.includes(user.role)) return <Navigate to=\"/\" replace />\n  return children\n}\n\nconst RoleRedirect = () => {\n  const { user } = useAuth()\n  if (!user) return <Navigate to=\"/login\" replace />\n  if (user.role === 'admin')    return <Navigate to=\"/admin\" replace />\n  if (user.role === 'manager')  return <Navigate to=\"/manager\" replace />\n  return <Navigate to=\"/employee\" replace />\n}\n\nexport default function App() {\n  return (\n    <AuthProvider>\n      <BrowserRouter>\n        <Toaster position=\"top-right\" toastOptions={{ duration: 3000 }} />\n        <Routes>\n          <Route path=\"/login\" element={<Login />} />\n          <Route path=\"/\" element={<RoleRedirect />} />\n\n          {/* Employee */}\n          <Route path=\"/employee\" element={<ProtectedRoute roles={['employee']}><Layout /></ProtectedRoute>}>\n            <Route index element={<EmployeeDashboard />} />\n            <Route path=\"goal-sheet\" element={<MyGoalSheet />} />\n            <Route path=\"goal-sheet/:id\" element={<GoalSheetDetail />} />\n          </Route>\n\n          {/* Manager */}\n          <Route path=\"/manager\" element={<ProtectedRoute roles={['manager','admin']}><Layout /></ProtectedRoute>}>\n            <Route index element={<ManagerDashboard />} />\n            <Route path=\"team\" element={<TeamGoalSheets />} />\n            <Route path=\"review/:id\" element={<ReviewSheet />} />\n          </Route>\n\n          {/* Admin */}\n          <Route path=\"/admin\" element={<ProtectedRoute roles={['admin']}><Layout /></ProtectedRoute>}>\n            <Route index element={<AdminDashboard />} />\n            <Route path=\"users\" element={<ManageUsers />} />\n            <Route path=\"cycles\" element={<ManageCycles />} />\n            <Route path=\"reports\" element={<Reports />} />\n          </Route>\n        </Routes>\n      </BrowserRouter>\n    </AuthProvider>\n  )\n}\n",
  "src/api/client.js": "import axios from 'axios'\n\nconst api = axios.create({ baseURL: '/api' })\n\n// Attach JWT token to every request\napi.interceptors.request.use((config) => {\n  const token = localStorage.getItem('token')\n  if (token) config.headers.Authorization = `Bearer ${token}`\n  return config\n})\n\n// Auto-logout on 401\napi.interceptors.response.use(\n  (res) => res,\n  (err) => {\n    if (err.response?.status === 401) {\n      localStorage.removeItem('token')\n      localStorage.removeItem('user')\n      window.location.href = '/login'\n    }\n    return Promise.reject(err)\n  }\n)\n\nexport default api\n",
  "src/context/AuthContext.jsx": "import { createContext, useContext, useState, useEffect } from 'react'\nimport api from '../api/client'\n\nconst AuthContext = createContext(null)\n\nexport const AuthProvider = ({ children }) => {\n  const [user, setUser] = useState(() => {\n    try { return JSON.parse(localStorage.getItem('user')) } catch { return null }\n  })\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    const token = localStorage.getItem('token')\n    if (token) {\n      api.get('/auth/me')\n        .then(r => setUser(r.data))\n        .catch(() => { localStorage.removeItem('token'); localStorage.removeItem('user') })\n        .finally(() => setLoading(false))\n    } else {\n      setLoading(false)\n    }\n  }, [])\n\n  const login = async (email, password) => {\n    const { data } = await api.post('/auth/login', { email, password })\n    localStorage.setItem('token', data.token)\n    localStorage.setItem('user', JSON.stringify(data.user))\n    setUser(data.user)\n    return data.user\n  }\n\n  const logout = () => {\n    localStorage.removeItem('token')\n    localStorage.removeItem('user')\n    setUser(null)\n  }\n\n  return (\n    <AuthContext.Provider value={{ user, login, logout, loading }}>\n      {children}\n    </AuthContext.Provider>\n  )\n}\n\nexport const useAuth = () => useContext(AuthContext)\n",
  "src/components/Layout.jsx": "import { Outlet, NavLink, useNavigate } from 'react-router-dom'\nimport { useAuth } from '../context/AuthContext'\nimport { LogOut, Target, Users, Settings, BarChart2, CheckSquare, Home, FileText } from 'lucide-react'\n\nconst navConfig = {\n  employee: [\n    { to: '/employee',            icon: Home,        label: 'Dashboard' },\n    { to: '/employee/goal-sheet', icon: Target,       label: 'My Goal Sheet' },\n  ],\n  manager: [\n    { to: '/manager',      icon: Home,        label: 'Dashboard' },\n    { to: '/manager/team', icon: Users,        label: 'Team Sheets' },\n  ],\n  admin: [\n    { to: '/admin',          icon: Home,       label: 'Dashboard' },\n    { to: '/admin/users',    icon: Users,      label: 'Users' },\n    { to: '/admin/cycles',   icon: Settings,   label: 'Cycles' },\n    { to: '/admin/reports',  icon: BarChart2,  label: 'Reports' },\n  ],\n}\n\nconst roleColors = {\n  employee: 'bg-blue-600',\n  manager:  'bg-emerald-600',\n  admin:    'bg-purple-600',\n}\n\nexport default function Layout() {\n  const { user, logout } = useAuth()\n  const navigate = useNavigate()\n  const links = navConfig[user?.role] || []\n\n  const handleLogout = () => { logout(); navigate('/login') }\n\n  return (\n    <div className=\"flex h-screen bg-gray-50\">\n      {/* Sidebar */}\n      <aside className=\"w-64 bg-gray-900 flex flex-col\">\n        {/* Logo */}\n        <div className=\"p-6 border-b border-gray-800\">\n          <div className=\"flex items-center gap-3\">\n            <div className={`w-8 h-8 rounded-lg ${roleColors[user?.role]} flex items-center justify-center`}>\n              <Target size={16} className=\"text-white\" />\n            </div>\n            <div>\n              <p className=\"text-white font-semibold text-sm\">AtomQuest</p>\n              <p className=\"text-gray-400 text-xs capitalize\">{user?.role} Portal</p>\n            </div>\n          </div>\n        </div>\n\n        {/* Nav */}\n        <nav className=\"flex-1 p-4 space-y-1\">\n          {links.map(({ to, icon: Icon, label }) => (\n            <NavLink\n              key={to}\n              to={to}\n              end={to.split('/').length === 2}\n              className={({ isActive }) =>\n                `flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-colors ${\n                  isActive\n                    ? 'bg-brand-600 text-white'\n                    : 'text-gray-400 hover:text-white hover:bg-gray-800'\n                }`\n              }\n            >\n              <Icon size={16} />\n              {label}\n            </NavLink>\n          ))}\n        </nav>\n\n        {/* User footer */}\n        <div className=\"p-4 border-t border-gray-800\">\n          <div className=\"flex items-center gap-3 mb-3\">\n            <div className=\"w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center\">\n              <span className=\"text-white text-xs font-medium\">{user?.name?.[0]?.toUpperCase()}</span>\n            </div>\n            <div className=\"flex-1 min-w-0\">\n              <p className=\"text-white text-sm font-medium truncate\">{user?.name}</p>\n              <p className=\"text-gray-400 text-xs truncate\">{user?.email}</p>\n            </div>\n          </div>\n          <button onClick={handleLogout} className=\"w-full flex items-center gap-2 px-3 py-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg text-sm transition-colors\">\n            <LogOut size={14} />\n            Sign out\n          </button>\n        </div>\n      </aside>\n\n      {/* Main content */}\n      <main className=\"flex-1 overflow-auto\">\n        <Outlet />\n      </main>\n    </div>\n  )\n}\n",
  "src/components/GoalCard.jsx": "import { useState } from 'react'\nimport api from '../api/client'\nimport toast from 'react-hot-toast'\nimport { Trash2, Edit2, Check, X, Lock } from 'lucide-react'\n\nexport default function GoalCard({ goal, canEdit, thrustAreas, sheetId, onUpdated }) {\n  const [editing, setEditing] = useState(false)\n  const [form, setForm] = useState({\n    title: goal.title,\n    description: goal.description || '',\n    weightage: goal.weightage,\n    uom_type: goal.uom_type,\n    target_value: goal.target_value || '',\n    thrust_area_id: goal.thrust_area_id || '',\n  })\n  const [saving, setSaving] = useState(false)\n\n  const save = async () => {\n    setSaving(true)\n    try {\n      await api.put(`/goals/${goal.id}`, form)\n      toast.success('Goal updated')\n      setEditing(false)\n      onUpdated()\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Update failed')\n    } finally {\n      setSaving(false)\n    }\n  }\n\n  const del = async () => {\n    if (!confirm('Delete this goal?')) return\n    try {\n      await api.delete(`/goals/${goal.id}`)\n      toast.success('Goal deleted')\n      onUpdated()\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Delete failed')\n    }\n  }\n\n  const uomLabels = { numeric_min: 'Numeric (\u2191)', numeric_max: 'Numeric (\u2193)', timeline: 'Timeline', zero: 'Zero-based' }\n\n  return (\n    <div className=\"card\">\n      {editing ? (\n        <div className=\"space-y-3\">\n          <input className=\"input font-medium\" value={form.title} onChange={e => setForm(f => ({...f, title: e.target.value}))} />\n          <textarea className=\"input\" rows={2} placeholder=\"Description\" value={form.description} onChange={e => setForm(f => ({...f, description: e.target.value}))} />\n          <div className=\"grid grid-cols-3 gap-3\">\n            <div>\n              <label className=\"label\">Thrust Area</label>\n              <select className=\"input\" value={form.thrust_area_id} onChange={e => setForm(f => ({...f, thrust_area_id: e.target.value}))}>\n                <option value=\"\">Select</option>\n                {thrustAreas.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}\n              </select>\n            </div>\n            <div>\n              <label className=\"label\">UoM Type</label>\n              <select className=\"input\" value={form.uom_type} onChange={e => setForm(f => ({...f, uom_type: e.target.value}))}>\n                <option value=\"numeric_min\">Numeric (higher is better)</option>\n                <option value=\"numeric_max\">Numeric (lower is better)</option>\n                <option value=\"timeline\">Timeline</option>\n                <option value=\"zero\">Zero-based</option>\n              </select>\n            </div>\n            <div>\n              <label className=\"label\">Target</label>\n              <input className=\"input\" type=\"number\" value={form.target_value} onChange={e => setForm(f => ({...f, target_value: e.target.value}))} />\n            </div>\n          </div>\n          <div>\n            <label className=\"label\">Weightage (%)</label>\n            <input className=\"input w-32\" type=\"number\" min=\"10\" max=\"100\" value={form.weightage} onChange={e => setForm(f => ({...f, weightage: e.target.value}))} />\n          </div>\n          <div className=\"flex gap-2\">\n            <button onClick={save} disabled={saving} className=\"btn-primary flex items-center gap-1\"><Check size={14} /> Save</button>\n            <button onClick={() => setEditing(false)} className=\"btn-secondary flex items-center gap-1\"><X size={14} /> Cancel</button>\n          </div>\n        </div>\n      ) : (\n        <div className=\"flex items-start justify-between\">\n          <div className=\"flex-1\">\n            <div className=\"flex items-center gap-2 mb-1\">\n              <h3 className=\"font-semibold text-gray-900\">{goal.title}</h3>\n              {goal.is_locked && <Lock size={12} className=\"text-gray-400\" />}\n              {goal.is_shared && <span className=\"text-xs bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded\">Shared</span>}\n            </div>\n            {goal.description && <p className=\"text-sm text-gray-500 mb-2\">{goal.description}</p>}\n            <div className=\"flex flex-wrap gap-3 text-xs text-gray-500\">\n              <span>{goal.thrust_area_name || 'No thrust area'}</span>\n              <span>\u00b7</span>\n              <span>{uomLabels[goal.uom_type]}</span>\n              <span>\u00b7</span>\n              <span>Target: {goal.target_value ?? '\u2014'}</span>\n            </div>\n          </div>\n          <div className=\"flex items-center gap-3 ml-4\">\n            <div className=\"text-right\">\n              <p className=\"text-2xl font-bold text-brand-600\">{goal.weightage}%</p>\n              <p className=\"text-xs text-gray-400\">weightage</p>\n            </div>\n            {canEdit && !goal.is_locked && (\n              <div className=\"flex gap-1\">\n                <button onClick={() => setEditing(true)} className=\"p-1.5 text-gray-400 hover:text-brand-600 hover:bg-brand-50 rounded-lg transition-colors\"><Edit2 size={14} /></button>\n                <button onClick={del} className=\"p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors\"><Trash2 size={14} /></button>\n              </div>\n            )}\n          </div>\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "src/components/AddGoalModal.jsx": "import { useState } from 'react'\nimport api from '../api/client'\nimport toast from 'react-hot-toast'\nimport { X, Loader2 } from 'lucide-react'\n\nexport default function AddGoalModal({ sheetId, thrustAreas, onClose, onAdded }) {\n  const [form, setForm] = useState({\n    title: '', description: '', thrust_area_id: '',\n    uom_type: 'numeric_min', target_value: '', target_date: '', weightage: 10,\n  })\n  const [loading, setLoading] = useState(false)\n\n  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))\n\n  const submit = async (e) => {\n    e.preventDefault()\n    if (form.weightage < 10) return toast.error('Minimum weightage is 10%')\n    setLoading(true)\n    try {\n      await api.post(`/goal-sheets/${sheetId}/goals`, {\n        ...form,\n        target_value: form.target_value ? Number(form.target_value) : null,\n        target_date: form.target_date || null,\n        thrust_area_id: form.thrust_area_id || null,\n      })\n      toast.success('Goal added!')\n      onAdded()\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Failed to add goal')\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  return (\n    <div className=\"fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4\">\n      <div className=\"bg-white rounded-2xl shadow-xl w-full max-w-lg\">\n        <div className=\"flex items-center justify-between p-6 border-b\">\n          <h2 className=\"text-lg font-semibold\">Add New Goal</h2>\n          <button onClick={onClose} className=\"text-gray-400 hover:text-gray-600\"><X size={20} /></button>\n        </div>\n        <form onSubmit={submit} className=\"p-6 space-y-4\">\n          <div>\n            <label className=\"label\">Goal Title *</label>\n            <input className=\"input\" required value={form.title} onChange={e => set('title', e.target.value)} placeholder=\"e.g. Increase sales revenue by 20%\" />\n          </div>\n          <div>\n            <label className=\"label\">Description</label>\n            <textarea className=\"input\" rows={2} value={form.description} onChange={e => set('description', e.target.value)} placeholder=\"Optional details...\" />\n          </div>\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"label\">Thrust Area</label>\n              <select className=\"input\" value={form.thrust_area_id} onChange={e => set('thrust_area_id', e.target.value)}>\n                <option value=\"\">Select area</option>\n                {thrustAreas.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}\n              </select>\n            </div>\n            <div>\n              <label className=\"label\">Unit of Measurement *</label>\n              <select className=\"input\" value={form.uom_type} onChange={e => set('uom_type', e.target.value)}>\n                <option value=\"numeric_min\">Numeric \u2014 higher is better</option>\n                <option value=\"numeric_max\">Numeric \u2014 lower is better</option>\n                <option value=\"timeline\">Timeline (date-based)</option>\n                <option value=\"zero\">Zero-based</option>\n              </select>\n            </div>\n          </div>\n          <div className=\"grid grid-cols-2 gap-4\">\n            {['timeline'].includes(form.uom_type) ? (\n              <div>\n                <label className=\"label\">Target Date *</label>\n                <input className=\"input\" type=\"date\" value={form.target_date} onChange={e => set('target_date', e.target.value)} />\n              </div>\n            ) : (\n              <div>\n                <label className=\"label\">Target Value {form.uom_type !== 'zero' ? '*' : ''}</label>\n                <input className=\"input\" type=\"number\" value={form.target_value} onChange={e => set('target_value', e.target.value)} placeholder=\"e.g. 100\" disabled={form.uom_type === 'zero'} />\n              </div>\n            )}\n            <div>\n              <label className=\"label\">Weightage (%) * <span className=\"text-gray-400 font-normal\">min 10%</span></label>\n              <input className=\"input\" type=\"number\" min=\"10\" max=\"100\" required value={form.weightage} onChange={e => set('weightage', Number(e.target.value))} />\n            </div>\n          </div>\n          <div className=\"flex gap-3 pt-2\">\n            <button type=\"submit\" disabled={loading} className=\"btn-primary flex items-center gap-2 flex-1 justify-center\">\n              {loading && <Loader2 size={14} className=\"animate-spin\" />}\n              Add Goal\n            </button>\n            <button type=\"button\" onClick={onClose} className=\"btn-secondary\">Cancel</button>\n          </div>\n        </form>\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/Login.jsx": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { useAuth } from '../context/AuthContext'\nimport toast from 'react-hot-toast'\nimport { Target, Loader2 } from 'lucide-react'\n\nexport default function Login() {\n  const { login } = useAuth()\n  const navigate = useNavigate()\n  const [form, setForm] = useState({ email: '', password: '' })\n  const [loading, setLoading] = useState(false)\n\n  const handleSubmit = async (e) => {\n    e.preventDefault()\n    setLoading(true)\n    try {\n      const user = await login(form.email, form.password)\n      toast.success(`Welcome back, ${user.name}!`)\n      if (user.role === 'admin')   return navigate('/admin')\n      if (user.role === 'manager') return navigate('/manager')\n      navigate('/employee')\n    } catch (err) {\n      toast.error(err.response?.data?.error || 'Login failed')\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  const fillDemo = (role) => {\n    const creds = {\n      admin:    { email: 'admin@atomquest.com',    password: 'Password123!' },\n      manager:  { email: 'manager@atomquest.com',  password: 'Password123!' },\n      employee: { email: 'employee@atomquest.com', password: 'Password123!' },\n    }\n    setForm(creds[role])\n  }\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-gray-900 via-brand-900 to-gray-900 flex items-center justify-center p-4\">\n      <div className=\"w-full max-w-md\">\n        {/* Logo */}\n        <div className=\"text-center mb-8\">\n          <div className=\"inline-flex items-center justify-center w-16 h-16 bg-brand-600 rounded-2xl mb-4\">\n            <Target size={32} className=\"text-white\" />\n          </div>\n          <h1 className=\"text-3xl font-bold text-white\">AtomQuest</h1>\n          <p className=\"text-gray-400 mt-1\">Goal Setting & Tracking Portal</p>\n        </div>\n\n        {/* Card */}\n        <div className=\"bg-white rounded-2xl shadow-xl p-8\">\n          <h2 className=\"text-xl font-semibold text-gray-900 mb-6\">Sign in to your account</h2>\n\n          <form onSubmit={handleSubmit} className=\"space-y-4\">\n            <div>\n              <label className=\"label\">Email address</label>\n              <input\n                type=\"email\" required\n                className=\"input\"\n                placeholder=\"you@company.com\"\n                value={form.email}\n                onChange={e => setForm(f => ({ ...f, email: e.target.value }))}\n              />\n            </div>\n            <div>\n              <label className=\"label\">Password</label>\n              <input\n                type=\"password\" required\n                className=\"input\"\n                placeholder=\"\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022\"\n                value={form.password}\n                onChange={e => setForm(f => ({ ...f, password: e.target.value }))}\n              />\n            </div>\n            <button type=\"submit\" disabled={loading} className=\"btn-primary w-full flex items-center justify-center gap-2 py-2.5\">\n              {loading && <Loader2 size={16} className=\"animate-spin\" />}\n              Sign in\n            </button>\n          </form>\n\n          {/* Demo shortcuts */}\n          <div className=\"mt-6 pt-6 border-t border-gray-100\">\n            <p className=\"text-xs text-gray-500 text-center mb-3\">Demo accounts</p>\n            <div className=\"grid grid-cols-3 gap-2\">\n              {['employee','manager','admin'].map(role => (\n                <button\n                  key={role}\n                  onClick={() => fillDemo(role)}\n                  className=\"text-xs py-1.5 px-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-50 capitalize transition-colors\"\n                >\n                  {role}\n                </button>\n              ))}\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/employee/Dashboard.jsx": "import { useEffect, useState } from 'react'\nimport { Link } from 'react-router-dom'\nimport { useAuth } from '../../context/AuthContext'\nimport api from '../../api/client'\nimport { Target, CheckCircle, Clock, AlertCircle, ArrowRight } from 'lucide-react'\n\nconst StatusBadge = ({ status }) => {\n  const map = { draft: 'badge-draft', submitted: 'badge-submitted', approved: 'badge-approved', returned: 'badge-returned' }\n  return <span className={map[status] || 'badge-draft'}>{status}</span>\n}\n\nexport default function EmployeeDashboard() {\n  const { user } = useAuth()\n  const [sheets, setSheets] = useState([])\n  const [cycle, setCycle] = useState(null)\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    Promise.all([\n      api.get('/cycles/active').catch(() => ({ data: null })),\n      api.get('/goal-sheets'),\n    ]).then(([c, s]) => {\n      setCycle(c.data)\n      setSheets(s.data)\n    }).finally(() => setLoading(false))\n  }, [])\n\n  const currentSheet = sheets.find(s => s.cycle_id === cycle?.id)\n\n  const stats = [\n    { label: 'Total Goals', value: currentSheet ? '\u2014' : '0', icon: Target, color: 'text-brand-600 bg-brand-50' },\n    { label: 'Approved', value: currentSheet?.status === 'approved' ? '\u2713' : '\u2014', icon: CheckCircle, color: 'text-green-600 bg-green-50' },\n    { label: 'Sheet Status', value: currentSheet?.status || 'No sheet', icon: Clock, color: 'text-amber-600 bg-amber-50' },\n    { label: 'Pending Action', value: currentSheet?.status === 'returned' ? '!' : '\u2014', icon: AlertCircle, color: 'text-red-600 bg-red-50' },\n  ]\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <div className=\"mb-8\">\n        <h1 className=\"text-2xl font-bold text-gray-900\">Welcome back, {user?.name} \ud83d\udc4b</h1>\n        <p className=\"text-gray-500 mt-1\">\n          {cycle ? `Active cycle: ${cycle.name}` : 'No active cycle at the moment'}\n        </p>\n      </div>\n\n      {/* Stats */}\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8\">\n        {stats.map(({ label, value, icon: Icon, color }) => (\n          <div key={label} className=\"card\">\n            <div className={`inline-flex p-2 rounded-lg ${color} mb-3`}>\n              <Icon size={18} />\n            </div>\n            <p className=\"text-2xl font-bold text-gray-900\">{value}</p>\n            <p className=\"text-sm text-gray-500\">{label}</p>\n          </div>\n        ))}\n      </div>\n\n      {/* Current sheet CTA */}\n      <div className=\"card\">\n        <div className=\"flex items-center justify-between mb-4\">\n          <h2 className=\"text-lg font-semibold text-gray-900\">Current Goal Sheet</h2>\n          {cycle && (\n            <Link to=\"/employee/goal-sheet\" className=\"btn-primary flex items-center gap-2\">\n              {currentSheet ? 'View Sheet' : 'Create Sheet'}\n              <ArrowRight size={14} />\n            </Link>\n          )}\n        </div>\n\n        {!cycle && (\n          <div className=\"text-center py-8 text-gray-400\">\n            <Target size={40} className=\"mx-auto mb-2 opacity-40\" />\n            <p>No active goal cycle. Check back later.</p>\n          </div>\n        )}\n\n        {cycle && !currentSheet && (\n          <div className=\"bg-amber-50 border border-amber-200 rounded-lg p-4\">\n            <p className=\"text-amber-800 text-sm font-medium\">Goal sheet not created yet</p>\n            <p className=\"text-amber-600 text-sm mt-1\">Create your goal sheet for {cycle.name} to get started.</p>\n          </div>\n        )}\n\n        {currentSheet && (\n          <div className=\"space-y-3\">\n            <div className=\"flex items-center justify-between py-3 border-b border-gray-100\">\n              <span className=\"text-sm text-gray-600\">Status</span>\n              <StatusBadge status={currentSheet.status} />\n            </div>\n            <div className=\"flex items-center justify-between py-3 border-b border-gray-100\">\n              <span className=\"text-sm text-gray-600\">Total Weightage</span>\n              <span className=\"text-sm font-medium\">{currentSheet.total_weightage || 0}%</span>\n            </div>\n            {currentSheet.return_reason && (\n              <div className=\"bg-red-50 border border-red-200 rounded-lg p-3\">\n                <p className=\"text-red-800 text-sm font-medium\">Returned \u2014 Manager feedback:</p>\n                <p className=\"text-red-600 text-sm mt-1\">{currentSheet.return_reason}</p>\n              </div>\n            )}\n          </div>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/employee/MyGoalSheet.jsx": "import { useEffect, useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { Plus, Send, Loader2, Target } from 'lucide-react'\nimport GoalCard from '../../components/GoalCard'\nimport AddGoalModal from '../../components/AddGoalModal'\n\nexport default function MyGoalSheet() {\n  const navigate = useNavigate()\n  const [cycle, setCycle] = useState(null)\n  const [sheet, setSheet] = useState(null)\n  const [goals, setGoals] = useState([])\n  const [thrustAreas, setThrustAreas] = useState([])\n  const [showAddGoal, setShowAddGoal] = useState(false)\n  const [loading, setLoading] = useState(true)\n  const [submitting, setSubmitting] = useState(false)\n\n  const load = async () => {\n    try {\n      const [c, s, t] = await Promise.all([\n        api.get('/cycles/active'),\n        api.get('/goal-sheets'),\n        api.get('/thrust-areas'),\n      ])\n      setCycle(c.data)\n      setThrustAreas(t.data)\n      const existing = s.data.find(sh => sh.cycle_id === c.data.id)\n      setSheet(existing || null)\n      if (existing) {\n        const full = await api.get(`/goal-sheets/${existing.id}`)\n        setGoals(full.data.goals || [])\n      }\n    } catch (e) {\n      toast.error('Failed to load data')\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  useEffect(() => { load() }, [])\n\n  const createSheet = async () => {\n    try {\n      const { data } = await api.post('/goal-sheets', { cycle_id: cycle.id })\n      setSheet(data)\n      toast.success('Goal sheet created!')\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Failed to create sheet')\n    }\n  }\n\n  const submitSheet = async () => {\n    setSubmitting(true)\n    try {\n      await api.post(`/goal-sheets/${sheet.id}/submit`)\n      toast.success('Goal sheet submitted for approval!')\n      load()\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Submission failed')\n    } finally {\n      setSubmitting(false)\n    }\n  }\n\n  const totalWeightage = goals.reduce((s, g) => s + Number(g.weightage), 0)\n  const weightageOk = Math.abs(totalWeightage - 100) < 0.01\n  const canEdit = sheet && ['draft', 'returned'].includes(sheet.status)\n  const canSubmit = canEdit && goals.length > 0 && weightageOk\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <div className=\"flex items-center justify-between mb-6\">\n        <div>\n          <h1 className=\"text-2xl font-bold text-gray-900\">My Goal Sheet</h1>\n          <p className=\"text-gray-500 text-sm mt-1\">{cycle?.name || 'No active cycle'}</p>\n        </div>\n        <div className=\"flex gap-3\">\n          {canEdit && (\n            <button onClick={() => setShowAddGoal(true)} disabled={goals.length >= 8} className=\"btn-secondary flex items-center gap-2\">\n              <Plus size={14} />\n              Add Goal {goals.length}/8\n            </button>\n          )}\n          {canSubmit && (\n            <button onClick={submitSheet} disabled={submitting} className=\"btn-primary flex items-center gap-2\">\n              {submitting ? <Loader2 size={14} className=\"animate-spin\" /> : <Send size={14} />}\n              Submit for Approval\n            </button>\n          )}\n        </div>\n      </div>\n\n      {/* No cycle */}\n      {!cycle && (\n        <div className=\"card text-center py-12 text-gray-400\">\n          <Target size={48} className=\"mx-auto mb-3 opacity-30\" />\n          <p>No active goal cycle.</p>\n        </div>\n      )}\n\n      {/* No sheet yet */}\n      {cycle && !sheet && (\n        <div className=\"card text-center py-12\">\n          <Target size={48} className=\"mx-auto mb-3 text-brand-300\" />\n          <h2 className=\"text-lg font-semibold text-gray-900 mb-2\">Create your goal sheet</h2>\n          <p className=\"text-gray-500 mb-6\">Start setting your goals for {cycle.name}</p>\n          <button onClick={createSheet} className=\"btn-primary mx-auto\">Create Goal Sheet</button>\n        </div>\n      )}\n\n      {/* Sheet exists */}\n      {sheet && (\n        <>\n          {/* Status bar */}\n          <div className=\"card mb-6 flex items-center justify-between\">\n            <div className=\"flex items-center gap-6\">\n              <div>\n                <p className=\"text-xs text-gray-500\">Status</p>\n                <span className={`badge-${sheet.status}`}>{sheet.status}</span>\n              </div>\n              <div>\n                <p className=\"text-xs text-gray-500\">Goals</p>\n                <p className=\"text-sm font-semibold\">{goals.length} / 8</p>\n              </div>\n              <div>\n                <p className=\"text-xs text-gray-500\">Total Weightage</p>\n                <p className={`text-sm font-semibold ${weightageOk ? 'text-green-600' : 'text-red-600'}`}>\n                  {totalWeightage.toFixed(1)}% {weightageOk ? '\u2713' : '(must be 100%)'}\n                </p>\n              </div>\n            </div>\n            {sheet.status === 'approved' && (\n              <span className=\"text-green-600 text-sm font-medium\">\u2713 Approved by manager</span>\n            )}\n          </div>\n\n          {/* Return reason */}\n          {sheet.return_reason && (\n            <div className=\"bg-red-50 border border-red-200 rounded-xl p-4 mb-6\">\n              <p className=\"text-red-800 font-medium text-sm\">Returned for revision</p>\n              <p className=\"text-red-600 text-sm mt-1\">{sheet.return_reason}</p>\n            </div>\n          )}\n\n          {/* Goals list */}\n          {goals.length === 0 ? (\n            <div className=\"card text-center py-10 text-gray-400\">\n              <p>No goals added yet. Click \"Add Goal\" to get started.</p>\n            </div>\n          ) : (\n            <div className=\"space-y-4\">\n              {goals.map(goal => (\n                <GoalCard\n                  key={goal.id}\n                  goal={goal}\n                  canEdit={canEdit}\n                  thrustAreas={thrustAreas}\n                  sheetId={sheet.id}\n                  onUpdated={load}\n                />\n              ))}\n            </div>\n          )}\n        </>\n      )}\n\n      {showAddGoal && (\n        <AddGoalModal\n          sheetId={sheet?.id}\n          thrustAreas={thrustAreas}\n          onClose={() => setShowAddGoal(false)}\n          onAdded={() => { setShowAddGoal(false); load() }}\n        />\n      )}\n    </div>\n  )\n}\n",
  "src/pages/employee/GoalSheetDetail.jsx": "import { useEffect, useState } from 'react'\nimport { useParams } from 'react-router-dom'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { Save, Loader2 } from 'lucide-react'\n\nconst QUARTERS = ['Q1', 'Q2', 'Q3', 'Q4']\n\nconst scoreLabel = (score) => {\n  if (score == null) return '\u2014'\n  return `${(score * 100).toFixed(1)}%`\n}\n\nexport default function GoalSheetDetail() {\n  const { id } = useParams()\n  const [sheet, setSheet] = useState(null)\n  const [loading, setLoading] = useState(true)\n  const [saving, setSaving] = useState({})\n\n  useEffect(() => {\n    api.get(`/goal-sheets/${id}`)\n      .then(r => setSheet(r.data))\n      .catch(() => toast.error('Failed to load sheet'))\n      .finally(() => setLoading(false))\n  }, [id])\n\n  const saveAchievement = async (goalId, quarter, data) => {\n    setSaving(s => ({ ...s, [`${goalId}-${quarter}`]: true }))\n    try {\n      await api.put(`/goals/${goalId}/achievements/${quarter}`, data)\n      toast.success('Achievement saved!')\n      const r = await api.get(`/goal-sheets/${id}`)\n      setSheet(r.data)\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Save failed')\n    } finally {\n      setSaving(s => ({ ...s, [`${goalId}-${quarter}`]: false }))\n    }\n  }\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n  if (!sheet) return <div className=\"p-8 text-gray-500\">Sheet not found.</div>\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-1\">Achievement Tracking</h1>\n      <p className=\"text-gray-500 mb-6\">{sheet.cycle_name}</p>\n\n      <div className=\"space-y-6\">\n        {sheet.goals?.map(goal => (\n          <div key={goal.id} className=\"card\">\n            <div className=\"flex items-start justify-between mb-4\">\n              <div>\n                <h3 className=\"font-semibold text-gray-900\">{goal.title}</h3>\n                <p className=\"text-sm text-gray-500\">{goal.thrust_area_name} \u00b7 {goal.uom_type} \u00b7 {goal.weightage}%</p>\n              </div>\n              <span className=\"text-sm text-gray-600\">Target: {goal.target_value ?? goal.target_date ?? '\u2014'}</span>\n            </div>\n\n            <div className=\"grid grid-cols-4 gap-4\">\n              {QUARTERS.map(q => {\n                const key = `${goal.id}-${q}`\n                const actual = goal[`${q.toLowerCase()}_actual`]\n                const status = goal[`${q.toLowerCase()}_status`] || 'not_started'\n                const score  = goal[`${q.toLowerCase()}_score`]\n                const [val, setVal] = useState(actual ?? '')\n                const [st,  setSt]  = useState(status)\n\n                return (\n                  <div key={q} className=\"bg-gray-50 rounded-lg p-3\">\n                    <p className=\"text-xs font-semibold text-gray-700 mb-2\">{q}</p>\n                    <input\n                      type=\"number\"\n                      className=\"input text-sm mb-2\"\n                      placeholder=\"Actual\"\n                      value={val}\n                      onChange={e => setVal(e.target.value)}\n                    />\n                    <select className=\"input text-sm mb-2\" value={st} onChange={e => setSt(e.target.value)}>\n                      <option value=\"not_started\">Not Started</option>\n                      <option value=\"on_track\">On Track</option>\n                      <option value=\"completed\">Completed</option>\n                    </select>\n                    <div className=\"flex items-center justify-between\">\n                      <span className=\"text-xs text-gray-500\">Score: {scoreLabel(score)}</span>\n                      <button\n                        onClick={() => saveAchievement(goal.id, q, { actual_value: val, status: st })}\n                        disabled={saving[key]}\n                        className=\"text-xs btn-primary py-1 px-2\"\n                      >\n                        {saving[key] ? <Loader2 size={10} className=\"animate-spin\" /> : <Save size={10} />}\n                      </button>\n                    </div>\n                  </div>\n                )\n              })}\n            </div>\n          </div>\n        ))}\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/manager/Dashboard.jsx": "import { useEffect, useState } from 'react'\nimport { Link } from 'react-router-dom'\nimport api from '../../api/client'\nimport { Users, CheckCircle, Clock, ArrowRight } from 'lucide-react'\n\nexport default function ManagerDashboard() {\n  const [sheets, setSheets] = useState([])\n  const [cycle, setCycle]   = useState(null)\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    Promise.all([\n      api.get('/cycles/active').catch(() => ({ data: null })),\n      api.get('/goal-sheets'),\n    ]).then(([c, s]) => { setCycle(c.data); setSheets(s.data) })\n      .finally(() => setLoading(false))\n  }, [])\n\n  const submitted = sheets.filter(s => s.status === 'submitted').length\n  const approved  = sheets.filter(s => s.status === 'approved').length\n  const pending   = sheets.filter(s => s.status === 'draft').length\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-1\">Manager Dashboard</h1>\n      <p className=\"text-gray-500 mb-8\">{cycle?.name || 'No active cycle'}</p>\n\n      <div className=\"grid grid-cols-3 gap-4 mb-8\">\n        {[\n          { label: 'Awaiting Approval', value: submitted, icon: Clock,        color: 'text-amber-600 bg-amber-50' },\n          { label: 'Approved',          value: approved,  icon: CheckCircle,  color: 'text-green-600 bg-green-50' },\n          { label: 'Not Submitted',     value: pending,   icon: Users,        color: 'text-gray-600 bg-gray-100' },\n        ].map(({ label, value, icon: Icon, color }) => (\n          <div key={label} className=\"card\">\n            <div className={`inline-flex p-2 rounded-lg ${color} mb-3`}><Icon size={18} /></div>\n            <p className=\"text-3xl font-bold text-gray-900\">{value}</p>\n            <p className=\"text-sm text-gray-500\">{label}</p>\n          </div>\n        ))}\n      </div>\n\n      <div className=\"card\">\n        <div className=\"flex items-center justify-between mb-4\">\n          <h2 className=\"text-lg font-semibold\">Team Goal Sheets</h2>\n          <Link to=\"/manager/team\" className=\"btn-secondary flex items-center gap-2 text-sm\">View All <ArrowRight size={14} /></Link>\n        </div>\n\n        {sheets.length === 0 ? (\n          <p className=\"text-gray-400 text-sm py-4 text-center\">No sheets submitted yet.</p>\n        ) : (\n          <div className=\"divide-y divide-gray-100\">\n            {sheets.slice(0, 5).map(s => (\n              <div key={s.id} className=\"flex items-center justify-between py-3\">\n                <div>\n                  <p className=\"font-medium text-gray-900 text-sm\">{s.employee_name}</p>\n                  <p className=\"text-xs text-gray-400\">{s.department}</p>\n                </div>\n                <div className=\"flex items-center gap-3\">\n                  <span className={`badge-${s.status}`}>{s.status}</span>\n                  {s.status === 'submitted' && (\n                    <Link to={`/manager/review/${s.id}`} className=\"btn-primary text-xs py-1 px-3\">Review</Link>\n                  )}\n                </div>\n              </div>\n            ))}\n          </div>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/manager/TeamGoalSheets.jsx": "import { useEffect, useState } from 'react'\nimport { Link } from 'react-router-dom'\nimport api from '../../api/client'\nimport { Search } from 'lucide-react'\n\nexport default function TeamGoalSheets() {\n  const [sheets, setSheets] = useState([])\n  const [cycle, setCycle]   = useState(null)\n  const [search, setSearch] = useState('')\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    Promise.all([\n      api.get('/cycles/active').catch(() => ({ data: null })),\n      api.get('/goal-sheets'),\n    ]).then(([c, s]) => { setCycle(c.data); setSheets(s.data) })\n      .finally(() => setLoading(false))\n  }, [])\n\n  const filtered = sheets.filter(s =>\n    s.employee_name?.toLowerCase().includes(search.toLowerCase()) ||\n    s.department?.toLowerCase().includes(search.toLowerCase())\n  )\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-6\">Team Goal Sheets</h1>\n\n      <div className=\"relative mb-6 max-w-xs\">\n        <Search size={16} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-400\" />\n        <input className=\"input pl-9\" placeholder=\"Search by name or department...\" value={search} onChange={e => setSearch(e.target.value)} />\n      </div>\n\n      <div className=\"card\">\n        <table className=\"w-full text-sm\">\n          <thead>\n            <tr className=\"text-left text-gray-500 border-b border-gray-100\">\n              <th className=\"pb-3 font-medium\">Employee</th>\n              <th className=\"pb-3 font-medium\">Department</th>\n              <th className=\"pb-3 font-medium\">Status</th>\n              <th className=\"pb-3 font-medium\">Weightage</th>\n              <th className=\"pb-3 font-medium\">Action</th>\n            </tr>\n          </thead>\n          <tbody className=\"divide-y divide-gray-50\">\n            {filtered.map(s => (\n              <tr key={s.id}>\n                <td className=\"py-3 font-medium text-gray-900\">{s.employee_name}</td>\n                <td className=\"py-3 text-gray-500\">{s.department}</td>\n                <td className=\"py-3\"><span className={`badge-${s.status}`}>{s.status}</span></td>\n                <td className=\"py-3 text-gray-500\">{s.total_weightage || 0}%</td>\n                <td className=\"py-3\">\n                  <Link to={`/manager/review/${s.id}`} className=\"text-brand-600 hover:underline text-xs\">\n                    {s.status === 'submitted' ? 'Review \u2192' : 'View \u2192'}\n                  </Link>\n                </td>\n              </tr>\n            ))}\n            {filtered.length === 0 && (\n              <tr><td colSpan={5} className=\"py-8 text-center text-gray-400\">No sheets found.</td></tr>\n            )}\n          </tbody>\n        </table>\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/manager/ReviewSheet.jsx": "import { useEffect, useState } from 'react'\nimport { useParams, useNavigate } from 'react-router-dom'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { CheckCircle, XCircle, MessageSquare, Loader2 } from 'lucide-react'\n\nexport default function ReviewSheet() {\n  const { id } = useParams()\n  const navigate = useNavigate()\n  const [sheet, setSheet] = useState(null)\n  const [loading, setLoading] = useState(true)\n  const [returnReason, setReturnReason] = useState('')\n  const [showReturn, setShowReturn] = useState(false)\n  const [checkinQ, setCheckinQ] = useState('Q1')\n  const [checkinComment, setCheckinComment] = useState('')\n  const [saving, setSaving] = useState(false)\n\n  const load = () => {\n    api.get(`/goal-sheets/${id}`)\n      .then(r => setSheet(r.data))\n      .catch(() => toast.error('Failed to load'))\n      .finally(() => setLoading(false))\n  }\n  useEffect(() => { load() }, [id])\n\n  const approve = async () => {\n    setSaving(true)\n    try {\n      await api.post(`/goal-sheets/${id}/approve`)\n      toast.success('Goal sheet approved!')\n      navigate('/manager/team')\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Approval failed')\n    } finally { setSaving(false) }\n  }\n\n  const returnSheet = async () => {\n    if (!returnReason.trim()) return toast.error('Please provide a return reason')\n    setSaving(true)\n    try {\n      await api.post(`/goal-sheets/${id}/return`, { return_reason: returnReason })\n      toast.success('Sheet returned for revision')\n      navigate('/manager/team')\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Failed')\n    } finally { setSaving(false) }\n  }\n\n  const submitCheckin = async () => {\n    if (!checkinComment.trim()) return toast.error('Comment required')\n    setSaving(true)\n    try {\n      await api.post(`/goal-sheets/${id}/checkins`, { quarter: checkinQ, comment: checkinComment })\n      toast.success('Check-in saved!')\n      setCheckinComment('')\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Failed')\n    } finally { setSaving(false) }\n  }\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n  if (!sheet)  return <div className=\"p-8 text-gray-500\">Sheet not found.</div>\n\n  const uomLabels = { numeric_min: '\u2191 Higher better', numeric_max: '\u2193 Lower better', timeline: 'Timeline', zero: 'Zero-based' }\n\n  return (\n    <div className=\"p-8 max-w-4xl\">\n      <div className=\"flex items-start justify-between mb-6\">\n        <div>\n          <h1 className=\"text-2xl font-bold text-gray-900\">Review Goal Sheet</h1>\n          <p className=\"text-gray-500 mt-1\">{sheet.employee_name} \u00b7 {sheet.department} \u00b7 {sheet.cycle_name}</p>\n        </div>\n        <span className={`badge-${sheet.status}`}>{sheet.status}</span>\n      </div>\n\n      {/* Goals */}\n      <div className=\"space-y-4 mb-8\">\n        {sheet.goals?.map(goal => (\n          <div key={goal.id} className=\"card\">\n            <div className=\"flex items-start justify-between\">\n              <div>\n                <h3 className=\"font-semibold text-gray-900\">{goal.title}</h3>\n                {goal.description && <p className=\"text-sm text-gray-500 mt-1\">{goal.description}</p>}\n                <div className=\"flex gap-4 mt-2 text-xs text-gray-400\">\n                  <span>{goal.thrust_area_name || 'No area'}</span>\n                  <span>{uomLabels[goal.uom_type]}</span>\n                  <span>Target: {goal.target_value ?? goal.target_date ?? '\u2014'}</span>\n                </div>\n              </div>\n              <span className=\"text-2xl font-bold text-brand-600 ml-4\">{goal.weightage}%</span>\n            </div>\n          </div>\n        ))}\n      </div>\n\n      {/* Total weightage */}\n      <div className=\"card mb-6 flex justify-between items-center\">\n        <span className=\"text-gray-700 font-medium\">Total Weightage</span>\n        <span className={`text-lg font-bold ${sheet.total_weightage === 100 ? 'text-green-600' : 'text-red-600'}`}>\n          {sheet.total_weightage}%\n        </span>\n      </div>\n\n      {/* Actions for submitted sheet */}\n      {sheet.status === 'submitted' && (\n        <div className=\"flex gap-3 mb-8\">\n          <button onClick={approve} disabled={saving} className=\"btn-primary flex items-center gap-2\">\n            {saving ? <Loader2 size={14} className=\"animate-spin\" /> : <CheckCircle size={14} />}\n            Approve\n          </button>\n          <button onClick={() => setShowReturn(!showReturn)} className=\"btn-danger flex items-center gap-2\">\n            <XCircle size={14} /> Return for Revision\n          </button>\n        </div>\n      )}\n\n      {showReturn && (\n        <div className=\"card mb-6\">\n          <label className=\"label\">Reason for returning *</label>\n          <textarea className=\"input mb-3\" rows={3} value={returnReason} onChange={e => setReturnReason(e.target.value)} placeholder=\"Explain what needs to be revised...\" />\n          <button onClick={returnSheet} disabled={saving} className=\"btn-danger flex items-center gap-2\">\n            {saving && <Loader2 size={14} className=\"animate-spin\" />} Confirm Return\n          </button>\n        </div>\n      )}\n\n      {/* Check-in section (approved sheets) */}\n      {sheet.status === 'approved' && (\n        <div className=\"card\">\n          <h2 className=\"text-lg font-semibold mb-4 flex items-center gap-2\">\n            <MessageSquare size={18} /> Quarterly Check-in\n          </h2>\n          <div className=\"grid grid-cols-2 gap-4 mb-4\">\n            <div>\n              <label className=\"label\">Quarter</label>\n              <select className=\"input\" value={checkinQ} onChange={e => setCheckinQ(e.target.value)}>\n                {['Q1','Q2','Q3','Q4'].map(q => <option key={q} value={q}>{q}</option>)}\n              </select>\n            </div>\n          </div>\n          <label className=\"label\">Check-in Comment *</label>\n          <textarea className=\"input mb-3\" rows={3} value={checkinComment} onChange={e => setCheckinComment(e.target.value)} placeholder=\"Provide structured feedback on employee progress...\" />\n          <button onClick={submitCheckin} disabled={saving} className=\"btn-primary flex items-center gap-2\">\n            {saving && <Loader2 size={14} className=\"animate-spin\" />}\n            <MessageSquare size={14} /> Save Check-in\n          </button>\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "src/pages/admin/Dashboard.jsx": "import { useEffect, useState } from 'react'\nimport { Link } from 'react-router-dom'\nimport api from '../../api/client'\nimport { Users, Settings, BarChart2, Shield, ArrowRight } from 'lucide-react'\n\nexport default function AdminDashboard() {\n  const [stats, setStats] = useState({ users: 0, sheets: 0, approved: 0, pending: 0 })\n  const [cycle, setCycle] = useState(null)\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    Promise.all([\n      api.get('/cycles/active').catch(() => ({ data: null })),\n      api.get('/users'),\n      api.get('/goal-sheets'),\n    ]).then(([c, u, s]) => {\n      setCycle(c.data)\n      setStats({\n        users:    u.data.length,\n        sheets:   s.data.length,\n        approved: s.data.filter(x => x.status === 'approved').length,\n        pending:  s.data.filter(x => x.status === 'submitted').length,\n      })\n    }).finally(() => setLoading(false))\n  }, [])\n\n  const cards = [\n    { to: '/admin/users',   icon: Users,    label: 'Manage Users',   value: stats.users,    sub: 'total users',    color: 'bg-blue-50 text-blue-600' },\n    { to: '/admin/cycles',  icon: Settings, label: 'Goal Cycles',    value: cycle?.name || '\u2014', sub: 'active cycle', color: 'bg-purple-50 text-purple-600' },\n    { to: '/admin/reports', icon: BarChart2, label: 'Reports',        value: stats.sheets,   sub: 'goal sheets',    color: 'bg-emerald-50 text-emerald-600' },\n    { to: '/admin/reports', icon: Shield,   label: 'Audit Trail',    value: stats.approved, sub: 'approved sheets', color: 'bg-amber-50 text-amber-600' },\n  ]\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-1\">Admin Dashboard</h1>\n      <p className=\"text-gray-500 mb-8\">Organisation overview \u2014 {cycle?.name || 'No active cycle'}</p>\n\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8\">\n        {cards.map(({ to, icon: Icon, label, value, sub, color }) => (\n          <Link key={label} to={to} className=\"card hover:shadow-md transition-shadow group\">\n            <div className={`inline-flex p-2 rounded-lg ${color} mb-3`}><Icon size={18} /></div>\n            <p className=\"text-2xl font-bold text-gray-900 mb-0.5\">{value}</p>\n            <p className=\"text-xs text-gray-400\">{sub}</p>\n            <p className=\"text-sm font-medium text-gray-600 mt-2 group-hover:text-brand-600 flex items-center gap-1\">\n              {label} <ArrowRight size={12} />\n            </p>\n          </Link>\n        ))}\n      </div>\n\n      {stats.pending > 0 && (\n        <div className=\"bg-amber-50 border border-amber-200 rounded-xl p-4\">\n          <p className=\"text-amber-800 font-medium\">{stats.pending} sheet(s) awaiting manager approval</p>\n          <p className=\"text-amber-600 text-sm mt-1\">Review the reports section to track completion across all managers.</p>\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "src/pages/admin/ManageUsers.jsx": "import { useEffect, useState } from 'react'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { UserPlus, Search } from 'lucide-react'\n\nconst ROLES = ['employee', 'manager', 'admin']\n\nexport default function ManageUsers() {\n  const [users, setUsers] = useState([])\n  const [managers, setManagers] = useState([])\n  const [search, setSearch] = useState('')\n  const [showAdd, setShowAdd] = useState(false)\n  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'employee', department: '', manager_id: '' })\n  const [loading, setLoading] = useState(true)\n\n  const load = () => {\n    Promise.all([api.get('/users'), api.get('/users/managers')])\n      .then(([u, m]) => { setUsers(u.data); setManagers(m.data) })\n      .finally(() => setLoading(false))\n  }\n  useEffect(() => { load() }, [])\n\n  const addUser = async (e) => {\n    e.preventDefault()\n    try {\n      await api.post('/auth/register', { ...form, manager_id: form.manager_id || null })\n      toast.success('User created!')\n      setShowAdd(false)\n      setForm({ name: '', email: '', password: '', role: 'employee', department: '', manager_id: '' })\n      load()\n    } catch (e) {\n      toast.error(e.response?.data?.error || 'Failed to create user')\n    }\n  }\n\n  const toggleActive = async (user) => {\n    try {\n      await api.put(`/users/${user.id}`, { ...user, is_active: !user.is_active })\n      toast.success(`User ${user.is_active ? 'deactivated' : 'activated'}`)\n      load()\n    } catch (e) {\n      toast.error('Failed to update user')\n    }\n  }\n\n  const filtered = users.filter(u =>\n    u.name?.toLowerCase().includes(search.toLowerCase()) ||\n    u.email?.toLowerCase().includes(search.toLowerCase()) ||\n    u.department?.toLowerCase().includes(search.toLowerCase())\n  )\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <div className=\"flex items-center justify-between mb-6\">\n        <h1 className=\"text-2xl font-bold text-gray-900\">Manage Users</h1>\n        <button onClick={() => setShowAdd(!showAdd)} className=\"btn-primary flex items-center gap-2\">\n          <UserPlus size={14} /> Add User\n        </button>\n      </div>\n\n      {showAdd && (\n        <div className=\"card mb-6\">\n          <h2 className=\"text-lg font-semibold mb-4\">New User</h2>\n          <form onSubmit={addUser} className=\"grid grid-cols-2 gap-4\">\n            <div><label className=\"label\">Name *</label><input className=\"input\" required value={form.name} onChange={e => setForm(f => ({...f, name: e.target.value}))} /></div>\n            <div><label className=\"label\">Email *</label><input className=\"input\" type=\"email\" required value={form.email} onChange={e => setForm(f => ({...f, email: e.target.value}))} /></div>\n            <div><label className=\"label\">Password *</label><input className=\"input\" type=\"password\" required minLength={6} value={form.password} onChange={e => setForm(f => ({...f, password: e.target.value}))} /></div>\n            <div><label className=\"label\">Department</label><input className=\"input\" value={form.department} onChange={e => setForm(f => ({...f, department: e.target.value}))} /></div>\n            <div>\n              <label className=\"label\">Role *</label>\n              <select className=\"input\" value={form.role} onChange={e => setForm(f => ({...f, role: e.target.value}))}>\n                {ROLES.map(r => <option key={r} value={r}>{r}</option>)}\n              </select>\n            </div>\n            <div>\n              <label className=\"label\">Manager</label>\n              <select className=\"input\" value={form.manager_id} onChange={e => setForm(f => ({...f, manager_id: e.target.value}))}>\n                <option value=\"\">No manager</option>\n                {managers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}\n              </select>\n            </div>\n            <div className=\"col-span-2 flex gap-3\">\n              <button type=\"submit\" className=\"btn-primary\">Create User</button>\n              <button type=\"button\" onClick={() => setShowAdd(false)} className=\"btn-secondary\">Cancel</button>\n            </div>\n          </form>\n        </div>\n      )}\n\n      <div className=\"relative mb-4 max-w-xs\">\n        <Search size={16} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-400\" />\n        <input className=\"input pl-9\" placeholder=\"Search users...\" value={search} onChange={e => setSearch(e.target.value)} />\n      </div>\n\n      <div className=\"card\">\n        <table className=\"w-full text-sm\">\n          <thead>\n            <tr className=\"text-left text-gray-500 border-b border-gray-100\">\n              {['Name','Email','Role','Department','Manager','Status','Action'].map(h => (\n                <th key={h} className=\"pb-3 font-medium\">{h}</th>\n              ))}\n            </tr>\n          </thead>\n          <tbody className=\"divide-y divide-gray-50\">\n            {filtered.map(u => (\n              <tr key={u.id}>\n                <td className=\"py-3 font-medium text-gray-900\">{u.name}</td>\n                <td className=\"py-3 text-gray-500\">{u.email}</td>\n                <td className=\"py-3\"><span className={`px-2 py-0.5 rounded-full text-xs font-medium ${u.role === 'admin' ? 'bg-purple-100 text-purple-700' : u.role === 'manager' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>{u.role}</span></td>\n                <td className=\"py-3 text-gray-500\">{u.department || '\u2014'}</td>\n                <td className=\"py-3 text-gray-500\">{u.manager_name || '\u2014'}</td>\n                <td className=\"py-3\"><span className={`text-xs ${u.is_active ? 'text-green-600' : 'text-red-500'}`}>{u.is_active ? 'Active' : 'Inactive'}</span></td>\n                <td className=\"py-3\">\n                  <button onClick={() => toggleActive(u)} className=\"text-xs text-gray-500 hover:text-brand-600\">\n                    {u.is_active ? 'Deactivate' : 'Activate'}\n                  </button>\n                </td>\n              </tr>\n            ))}\n          </tbody>\n        </table>\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/admin/ManageCycles.jsx": "import { useEffect, useState } from 'react'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { Plus, Zap } from 'lucide-react'\n\nexport default function ManageCycles() {\n  const [cycles, setCycles] = useState([])\n  const [thrustAreas, setThrustAreas] = useState([])\n  const [showForm, setShowForm] = useState(false)\n  const [showThrust, setShowThrust] = useState(false)\n  const [form, setForm] = useState({ name: '', start_date: '', end_date: '', goal_setting_opens: '', q1_opens: '', q2_opens: '', q3_opens: '', q4_opens: '' })\n  const [thrustForm, setThrustForm] = useState({ name: '', description: '' })\n  const [loading, setLoading] = useState(true)\n\n  const load = () => {\n    Promise.all([api.get('/cycles'), api.get('/thrust-areas')])\n      .then(([c, t]) => { setCycles(c.data); setThrustAreas(t.data) })\n      .finally(() => setLoading(false))\n  }\n  useEffect(() => { load() }, [])\n\n  const createCycle = async (e) => {\n    e.preventDefault()\n    try {\n      await api.post('/cycles', form)\n      toast.success('Cycle created!')\n      setShowForm(false)\n      load()\n    } catch (e) { toast.error(e.response?.data?.error || 'Failed') }\n  }\n\n  const activate = async (id) => {\n    try {\n      await api.post(`/cycles/${id}/activate`)\n      toast.success('Cycle activated!')\n      load()\n    } catch (e) { toast.error('Failed to activate') }\n  }\n\n  const createThrust = async (e) => {\n    e.preventDefault()\n    try {\n      await api.post('/thrust-areas', thrustForm)\n      toast.success('Thrust area created!')\n      setThrustForm({ name: '', description: '' })\n      setShowThrust(false)\n      load()\n    } catch (e) { toast.error('Failed') }\n  }\n\n  if (loading) return <div className=\"p-8 text-gray-500\">Loading...</div>\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-6\">Goal Cycles & Thrust Areas</h1>\n\n      {/* Cycles */}\n      <div className=\"flex items-center justify-between mb-4\">\n        <h2 className=\"text-lg font-semibold\">Goal Cycles</h2>\n        <button onClick={() => setShowForm(!showForm)} className=\"btn-primary flex items-center gap-2\"><Plus size={14} /> New Cycle</button>\n      </div>\n\n      {showForm && (\n        <div className=\"card mb-6\">\n          <h3 className=\"font-semibold mb-4\">New Cycle</h3>\n          <form onSubmit={createCycle} className=\"grid grid-cols-2 gap-4\">\n            <div className=\"col-span-2\"><label className=\"label\">Cycle Name *</label><input className=\"input\" required value={form.name} onChange={e => setForm(f => ({...f, name: e.target.value}))} placeholder=\"e.g. FY 2026-27\" /></div>\n            {[['start_date','Start Date'],['end_date','End Date'],['goal_setting_opens','Goal Setting Opens'],['q1_opens','Q1 Opens'],['q2_opens','Q2 Opens'],['q3_opens','Q3 Opens'],['q4_opens','Q4 Opens']].map(([k, l]) => (\n              <div key={k}><label className=\"label\">{l}</label><input className=\"input\" type=\"date\" value={form[k]} onChange={e => setForm(f => ({...f, [k]: e.target.value}))} /></div>\n            ))}\n            <div className=\"col-span-2 flex gap-3\">\n              <button type=\"submit\" className=\"btn-primary\">Create</button>\n              <button type=\"button\" onClick={() => setShowForm(false)} className=\"btn-secondary\">Cancel</button>\n            </div>\n          </form>\n        </div>\n      )}\n\n      <div className=\"card mb-8\">\n        <table className=\"w-full text-sm\">\n          <thead><tr className=\"text-left text-gray-500 border-b border-gray-100\">\n            {['Name','Start','End','Status','Action'].map(h => <th key={h} className=\"pb-3 font-medium\">{h}</th>)}\n          </tr></thead>\n          <tbody className=\"divide-y divide-gray-50\">\n            {cycles.map(c => (\n              <tr key={c.id}>\n                <td className=\"py-3 font-medium text-gray-900\">{c.name}</td>\n                <td className=\"py-3 text-gray-500\">{c.start_date?.slice(0,10)}</td>\n                <td className=\"py-3 text-gray-500\">{c.end_date?.slice(0,10)}</td>\n                <td className=\"py-3\">{c.is_active ? <span className=\"badge-approved\">Active</span> : <span className=\"badge-draft\">Inactive</span>}</td>\n                <td className=\"py-3\">\n                  {!c.is_active && (\n                    <button onClick={() => activate(c.id)} className=\"text-xs flex items-center gap-1 text-amber-600 hover:text-amber-700\">\n                      <Zap size={12} /> Activate\n                    </button>\n                  )}\n                </td>\n              </tr>\n            ))}\n            {cycles.length === 0 && <tr><td colSpan={5} className=\"py-6 text-center text-gray-400\">No cycles yet.</td></tr>}\n          </tbody>\n        </table>\n      </div>\n\n      {/* Thrust Areas */}\n      <div className=\"flex items-center justify-between mb-4\">\n        <h2 className=\"text-lg font-semibold\">Thrust Areas</h2>\n        <button onClick={() => setShowThrust(!showThrust)} className=\"btn-secondary flex items-center gap-2\"><Plus size={14} /> Add Area</button>\n      </div>\n\n      {showThrust && (\n        <div className=\"card mb-4\">\n          <form onSubmit={createThrust} className=\"flex gap-3\">\n            <input className=\"input flex-1\" required placeholder=\"Thrust area name\" value={thrustForm.name} onChange={e => setThrustForm(f => ({...f, name: e.target.value}))} />\n            <input className=\"input flex-1\" placeholder=\"Description (optional)\" value={thrustForm.description} onChange={e => setThrustForm(f => ({...f, description: e.target.value}))} />\n            <button type=\"submit\" className=\"btn-primary whitespace-nowrap\">Add</button>\n          </form>\n        </div>\n      )}\n\n      <div className=\"card\">\n        <div className=\"divide-y divide-gray-100\">\n          {thrustAreas.map(t => (\n            <div key={t.id} className=\"py-3 flex items-center justify-between\">\n              <div>\n                <p className=\"font-medium text-gray-900 text-sm\">{t.name}</p>\n                {t.description && <p className=\"text-xs text-gray-400\">{t.description}</p>}\n              </div>\n              <span className=\"text-xs text-green-600\">Active</span>\n            </div>\n          ))}\n          {thrustAreas.length === 0 && <p className=\"py-6 text-center text-gray-400 text-sm\">No thrust areas yet.</p>}\n        </div>\n      </div>\n    </div>\n  )\n}\n",
  "src/pages/admin/Reports.jsx": "import { useEffect, useState } from 'react'\nimport api from '../../api/client'\nimport toast from 'react-hot-toast'\nimport { Download, RefreshCw } from 'lucide-react'\n\nexport default function Reports() {\n  const [cycles, setCycles] = useState([])\n  const [cycleId, setCycleId] = useState('')\n  const [quarter, setQuarter] = useState('')\n  const [completion, setCompletion] = useState(null)\n  const [audit, setAudit] = useState([])\n  const [loading, setLoading] = useState(false)\n\n  useEffect(() => {\n    api.get('/cycles').then(r => {\n      setCycles(r.data)\n      const active = r.data.find(c => c.is_active)\n      if (active) setCycleId(active.id)\n    })\n  }, [])\n\n  const loadReports = async () => {\n    if (!cycleId) return toast.error('Select a cycle first')\n    setLoading(true)\n    try {\n      const [comp, aud] = await Promise.all([\n        api.get('/reports/completion', { params: { cycle_id: cycleId, quarter: quarter || undefined } }),\n        api.get('/reports/audit'),\n      ])\n      setCompletion(comp.data)\n      setAudit(aud.data)\n    } catch (e) {\n      toast.error('Failed to load reports')\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  const downloadCSV = () => {\n    if (!cycleId) return toast.error('Select a cycle first')\n    const url = `/api/reports/achievements?cycle_id=${cycleId}&format=csv`\n    const a = document.createElement('a')\n    a.href = url\n    a.download = `achievement_report.csv`\n    a.click()\n  }\n\n  return (\n    <div className=\"p-8\">\n      <h1 className=\"text-2xl font-bold text-gray-900 mb-6\">Reports & Analytics</h1>\n\n      {/* Controls */}\n      <div className=\"card mb-6\">\n        <div className=\"flex items-end gap-4\">\n          <div className=\"flex-1\">\n            <label className=\"label\">Goal Cycle</label>\n            <select className=\"input\" value={cycleId} onChange={e => setCycleId(e.target.value)}>\n              <option value=\"\">Select cycle</option>\n              {cycles.map(c => <option key={c.id} value={c.id}>{c.name}{c.is_active ? ' (active)' : ''}</option>)}\n            </select>\n          </div>\n          <div>\n            <label className=\"label\">Quarter (optional)</label>\n            <select className=\"input\" value={quarter} onChange={e => setQuarter(e.target.value)}>\n              <option value=\"\">All quarters</option>\n              {['Q1','Q2','Q3','Q4'].map(q => <option key={q} value={q}>{q}</option>)}\n            </select>\n          </div>\n          <button onClick={loadReports} disabled={loading} className=\"btn-primary flex items-center gap-2\">\n            <RefreshCw size={14} className={loading ? 'animate-spin' : ''} /> Load\n          </button>\n          <button onClick={downloadCSV} className=\"btn-secondary flex items-center gap-2\">\n            <Download size={14} /> Export CSV\n          </button>\n        </div>\n      </div>\n\n      {/* Completion Dashboard */}\n      {completion && (\n        <>\n          <h2 className=\"text-lg font-semibold mb-4\">Completion Dashboard</h2>\n          <div className=\"card mb-6\">\n            <table className=\"w-full text-sm\">\n              <thead><tr className=\"text-left text-gray-500 border-b border-gray-100\">\n                {['Employee','Department','Manager','Sheet Status','Submitted','Approved'].map(h => <th key={h} className=\"pb-3 font-medium\">{h}</th>)}\n              </tr></thead>\n              <tbody className=\"divide-y divide-gray-50\">\n                {completion.employees.map(e => (\n                  <tr key={e.id}>\n                    <td className=\"py-2.5 font-medium text-gray-900\">{e.name}</td>\n                    <td className=\"py-2.5 text-gray-500\">{e.department || '\u2014'}</td>\n                    <td className=\"py-2.5 text-gray-500\">{e.manager_name || '\u2014'}</td>\n                    <td className=\"py-2.5\"><span className={`badge-${e.sheet_status || 'draft'}`}>{e.sheet_status || 'not started'}</span></td>\n                    <td className=\"py-2.5 text-gray-500\">{e.submitted_at ? new Date(e.submitted_at).toLocaleDateString() : '\u2014'}</td>\n                    <td className=\"py-2.5 text-gray-500\">{e.approved_at ? new Date(e.approved_at).toLocaleDateString() : '\u2014'}</td>\n                  </tr>\n                ))}\n              </tbody>\n            </table>\n          </div>\n\n          {/* Manager check-in completion */}\n          {completion.manager_checkins?.length > 0 && (\n            <>\n              <h2 className=\"text-lg font-semibold mb-4\">Manager Check-in Completion</h2>\n              <div className=\"card mb-6\">\n                <table className=\"w-full text-sm\">\n                  <thead><tr className=\"text-left text-gray-500 border-b border-gray-100\">\n                    {['Manager','Total Reports','Check-ins Done','Completion %'].map(h => <th key={h} className=\"pb-3 font-medium\">{h}</th>)}\n                  </tr></thead>\n                  <tbody className=\"divide-y divide-gray-50\">\n                    {completion.manager_checkins.map(m => (\n                      <tr key={m.id}>\n                        <td className=\"py-2.5 font-medium text-gray-900\">{m.manager_name}</td>\n                        <td className=\"py-2.5 text-gray-500\">{m.total_reports}</td>\n                        <td className=\"py-2.5 text-gray-500\">{m.checkins_done}</td>\n                        <td className=\"py-2.5\">\n                          <div className=\"flex items-center gap-2\">\n                            <div className=\"flex-1 bg-gray-200 rounded-full h-1.5 max-w-[80px]\">\n                              <div className=\"bg-brand-600 h-1.5 rounded-full\" style={{ width: `${m.completion_pct || 0}%` }} />\n                            </div>\n                            <span className={m.completion_pct >= 100 ? 'text-green-600' : 'text-amber-600'}>{m.completion_pct || 0}%</span>\n                          </div>\n                        </td>\n                      </tr>\n                    ))}\n                  </tbody>\n                </table>\n              </div>\n            </>\n          )}\n        </>\n      )}\n\n      {/* Audit Trail */}\n      {audit.length > 0 && (\n        <>\n          <h2 className=\"text-lg font-semibold mb-4\">Audit Trail</h2>\n          <div className=\"card\">\n            <table className=\"w-full text-sm\">\n              <thead><tr className=\"text-left text-gray-500 border-b border-gray-100\">\n                {['Time','Entity','Action','Changed By','Notes'].map(h => <th key={h} className=\"pb-3 font-medium\">{h}</th>)}\n              </tr></thead>\n              <tbody className=\"divide-y divide-gray-50\">\n                {audit.slice(0, 50).map(a => (\n                  <tr key={a.id}>\n                    <td className=\"py-2.5 text-gray-400 text-xs\">{new Date(a.created_at).toLocaleString()}</td>\n                    <td className=\"py-2.5 text-gray-600\">{a.entity_type}</td>\n                    <td className=\"py-2.5\"><span className=\"bg-gray-100 text-gray-700 text-xs px-2 py-0.5 rounded\">{a.action}</span></td>\n                    <td className=\"py-2.5 text-gray-700\">{a.changed_by_name}</td>\n                    <td className=\"py-2.5 text-gray-400 text-xs\">{a.notes || '\u2014'}</td>\n                  </tr>\n                ))}\n              </tbody>\n            </table>\n          </div>\n        </>\n      )}\n\n      {!completion && !loading && (\n        <div className=\"card text-center py-12 text-gray-400\">\n          <p>Select a cycle and click Load to view reports.</p>\n        </div>\n      )}\n    </div>\n  )\n}\n"
};

console.log("🚀 Setting up AtomQuest Frontend...");

for (const [filePath, content] of Object.entries(files)) {
  const dir = path.dirname(filePath);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, { encoding: 'utf8' });
  console.log('  wrote:', filePath);
}

console.log("\n📦 Installing dependencies...");
execSync('npm install react react-dom react-router-dom axios react-hot-toast lucide-react', { stdio: 'inherit' });
execSync('npm install -D vite @vitejs/plugin-react tailwindcss@3 postcss autoprefixer', { stdio: 'inherit' });

console.log("\n✅ Frontend ready! Run: npm run dev");
console.log("   Opens at: http://localhost:5173");
